arguments.file_text:
@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>

<div class="mb-3">
    <label class="form-label">Filter by Status:</label>
    <select class="form-select w-auto d-inline-block" @bind="selectedStatusFilter">
        <option value="">All</option>
        @foreach (var status in Enum.GetValues<ShipmentStatus>())
        {
            <option value="@status">@status</option>
        }
    </select>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Customer</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>@shipment.CustomerEmail</td>
                    <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string selectedStatusFilter = "";

    private IEnumerable<Shipment> FilteredShipments =>
        string.IsNullOrEmpty(selectedStatusFilter)
            ? shipments ?? []
            : shipments?.Where(s => s.Status.ToString() == selectedStatusFilter) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Exception => "danger",
        _ => "secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput" />
            <button class="btn btn-primary" @onclick="SearchShipment">Track</button>
        </div>
    </div>
</div>

@if (searchPerformed && trackedShipment is null)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}

@if (trackedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5>Shipment: @trackedShipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Description:</strong> @trackedShipment.Description</p>
                    <p><strong>Origin:</strong> @trackedShipment.Origin</p>
                    <p><strong>Destination:</strong> @trackedShipment.Destination</p>
                    <p><strong>Created:</strong> @trackedShipment.CreatedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @trackedShipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</p>
                </div>
                <div class="col-md-6">
                    <h6>Status Timeline</h6>
                    <div class="list-group">
                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
                        {
                            var isActive = (int)status <= (int)trackedShipment.Status;
                            var isCurrent = status == trackedShipment.Status;
                            <div class="list-group-item @(isCurrent ? "list-group-item-primary" : isActive ? "list-group-item-success" : "")">
                                @if (isActive)
                                {
                                    <span>&#10003; </span>
                                }
                                @status
                                @if (isCurrent)
                                {
                                    <span class="badge bg-primary float-end">Current</span>
                                }
                            </div>
                        }
                    </div>
                </div>
            </div>
        </div>
    </div>
}

<h3 class="mt-4">My Shipments</h3>

@if (myShipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (myShipments.Count == 0)
{
    <p>You have no shipments.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in myShipments)
            {
                <tr>
                    <td>
                        <a href="javascript:void(0)" @onclick="() => TrackExisting(shipment.TrackingNumber)">
                            @shipment.TrackingNumber
                        </a>
                    </td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string trackingNumber = "";
    private Shipment? trackedShipment;
    private List<Shipment>? myShipments;
    private bool searchPerformed;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await ShipmentService.GetShipmentsForCustomerAsync();
    }

    private async Task SearchShipment()
    {
        searchPerformed = true;
        if (!string.IsNullOrWhiteSpace(trackingNumber))
        {
            trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        }
    }

    private async Task TrackExisting(string tracking)
    {
        trackingNumber = tracking;
        await SearchShipment();
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Exception => "danger",
        _ => "secondary"
    };
}

